1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ---- Simplest cases / processing fee ----
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // ---- Base premiums for each main item type ----
15	  it.todo("single sword (newcomer, first contract) → 100 base + 10 first-insurance + 5 fee = 115 G");
16	  it.todo("single amulet (newcomer, first contract) → 60 base + 6 first-insurance + 5 fee = 71 G");
17	  it.todo("single staff (newcomer, first contract) → 80 base + 8 first-insurance + 5 fee = 93 G");
18	  it.todo("single potion (newcomer, first contract) → 40 base + 4 first-insurance + 5 fee = 49 G");
19	
20	  // ---- Components and blocks ----
21	  it.todo("2 runes → 50 G base premium (no block)");
22	  it.todo("3 runes → 60 G base premium (block applies)");
23	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
24	  it.todo("7 runes → 175 G base premium (no block — block requires exactly 3)");
25	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
26	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
27	
28	  // ---- Item-specific modifiers ----
29	  it.todo("cursed item adds 50% risk surcharge to that item's base premium");
30	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% risk surcharge");
31	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
32	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
33	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
34	
35	  // ---- Policy-wide modifiers ----
36	  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy base");
37	  it.todo("customer with exactly 2 years → loyalty discount applies");
38	  it.todo("first insurance carries 10% surcharge per item");
39	  it.todo("each contract after the first gets 15% follow-up discount");
40	
41	  // ---- Modifier scope on multi-item policies ----
42	  it.todo("cursed sword + plain amulet → 160 base + 50 curse = 210 G before further modifiers and fee");
43	  it.todo("item-specific modifiers apply per item; policy-wide modifiers apply to policy base; fee added last");
44	
45	  // ---- Rounding ----
46	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
47	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
48	  it.todo("intermediate amounts kept as fractions; only final premium or payout rounded");
49	
50	  // ---- Integration premium examples ----
51	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G (100 + 50 + 10 + 5 fee)");
52	  it.todo("long-standing (3 yr) second contract with cursed sword (steel, ench 7) → 160 G");
53	  it.todo("first insurance surcharge still applies per item even on follow-up contract");
54	
55	  // ---- Claim: standard reimbursement ----
56	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
57	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");
58	
59	  // ---- Claim: enchantment threshold ----
60	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
61	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");
62	
63	  // ---- Claim: dragon material ----
64	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
65	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
66	
67	  // ---- Claim: deductible per damage event ----
68	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (100 deductible per item)");
69	
70	  // ---- Claim: multiple items of same type ----
71	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
72	  it.todo("two sword damages on policy with two swords → each treated as separate damage with its own deductible");
73	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero, claim rejected");
74	
75	  // ---- Claim: cap exhaustion ----
76	  it.todo("policy with sword + amulet → insurance sum 1600 G, cap 3200 G");
77	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; premium modifiers don't raise cap)");
78	  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 G; block discount affects premium only");
79	  it.todo("sword insured, cap 2000; two claims of 1500 — first payout 1400 (cap remaining 600), second payout 600 (cap remaining 0)");
80	
81	  // ---- Error / edge cases ----
82	  it.todo("quote includes item with unknown type (e.g. broomstick) → CLI exits non-zero, error to stderr, no results to stdout");
83	  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero, error to stderr");
84	  it.todo("claim contains a damage entry with amount: -200 → CLI exits non-zero, error to stderr");
85	
86	  // ---- CLI / schema integration ----
87	  it.todo("schema example: amulet quote then fire claim of 200 returns premium and payout/remainingCap");
88	});
89

1	export type QuoteStep = { op: "quote"; items: Array<Record<string, unknown>> };
2	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<{ itemType: string; amount: number }> } };
3	export type Step = QuoteStep | ClaimStep;
4	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	export type QuoteResult = { premium: number };
6	export type ClaimResult = { payout: number; remainingCap: number };
7	export type ScenarioResult = { results: Array<QuoteResult | ClaimResult> };
8	
9	export const runScenario = (_scenario: Scenario): ScenarioResult => {
10	  return { results: [{ premium: 5 }] };
11	};
